1	import { useState } from "react";
2	import { View, Text } from "@tarojs/components";
3	import Taro, { useDidShow } from "@tarojs/taro";
4	import { apiFetch, getToday, getDomains } from "../../lib";
5	import Icon from "../../components/Icon";
6	import "./index.scss";
7	
8	interface HabitWithLogs {
9	  id: string;
10	  title: string;
11	  domainId: string;
12	  frequency: string;
13	  logs: { date: string; completed: boolean }[];
14	}
15	
16	export default function StatsPage() {
17	  const [habits, setHabits] = useState<HabitWithLogs[]>([]);
18	  const [loading, setLoading] = useState(true);
19	  const [range, setRange] = useState<"week" | "month">("week");
20	
21	  useDidShow(() => { fetchStats(); });
22	
23	  async function fetchStats() {
24	    try {
25	      const data = await apiFetch(`/api/stats?range=${range}`);
26	      setHabits(data.habits || []);
27	    } catch {
28	      Taro.showToast({ title: "获取统计数据失败", icon: "none" });
29	    }
30	    setLoading(false);
31	  }
32	
33	  const totalChecks = habits.reduce((sum, h) => sum + h.logs.filter((l) => l.completed).length, 0);
34	  const totalPossible = habits.reduce((sum, h) => {
35	    const days = range === "week" ? 7 : 30;
36	    if (h.frequency === "daily") return sum + days;
37	    if (h.frequency === "weekly") return sum + Math.ceil(days / 7);
38	    if (h.frequency === "weekday") return sum + countWeekdays(days);
39	    return sum + days;
40	  }, 0);
41	  const overallRate = totalPossible > 0 ? Math.round((totalChecks / totalPossible) * 100) : 0;
42	
43	  const domainStats = getDomains().map((d) => {
44	    const domainHabits = habits.filter((h) => h.domainId === d.name);
45	    const completed = domainHabits.reduce((sum, h) => sum + h.logs.filter((l) => l.completed).length, 0);
46	    const possible = domainHabits.reduce((sum, h) => {
47	      const days = range === "week" ? 7 : 30;
48	      if (h.frequency === "daily") return sum + days;
49	      if (h.frequency === "weekly") return sum + Math.ceil(days / 7);
50	      if (h.frequency === "weekday") return sum + countWeekdays(days);
51	      return sum + days;
52	    }, 0);
53	    return { name: d.name, icon: d.icon, rate: possible > 0 ? Math.round((completed / possible) * 100) : 0, color: d.color };
54	  });
55	
56	  // Bar chart data
57	  const days = range === "week" ? 7 : 30;
58	  const barData = Array.from({ length: days }, (_, i) => {
59	    const d = new Date();
60	    d.setDate(d.getDate() - (days - 1 - i));
61	    const dateStr = d.toISOString().split("T")[0];
62	    const completed = habits.filter((h) => h.logs.some((l) => l.date === dateStr && l.completed)).length;
63	    const maxH = habits.length || 1;
64	    return {
65	      label: d.toLocaleDateString("zh-CN", { day: "numeric" }),
66	      completed,
67	      pct: Math.round((completed / maxH) * 100),
68	    };
69	  });
70	
71	  const streakDays = calcStreak(habits);
72	
73	  if (loading) {
74	    return (
75	      <View className="page">
76	        <Text className="page-title">数据统计</Text>
77	        <Text className="page-subtitle">看见进步，持续精进</Text>
78	        <View className="metrics">
79	          <View className="metric"><View className="skeleton-line w-60" style={{ margin: "0 auto" }} /><Text className="metric-label" style={{ marginTop: "var(--space-md)" }}>总完成率</Text></View>
80	          <View className="metric"><View className="skeleton-line w-60" style={{ margin: "0 auto" }} /><Text className="metric-label" style={{ marginTop: "var(--space-md)" }}>总打卡数</Text></View>
81	        </View>
82	        <View className="skeleton-lines" style={{ marginTop: "var(--space-xl)" }}>
83	          <View className="skeleton-line w-80" />
84	          <View className="skeleton-line w-60" />
85	        </View>
86	      </View>
87	    );
88	  }
89	
90	  return (
91	    <View className="page">
92	      <Text className="page-title">数据统计</Text>
93	      <Text className="page-subtitle">看见进步，持续精进</Text>
94	
95	      <View className="range-tabs">
96	        <Text className={`range-tab ${range === "week" ? "active" : ""}`} onClick={() => { setRange("week"); fetchStats(); }}>本周</Text>
97	        <Text className={`range-tab ${range === "month" ? "active" : ""}`} onClick={() => { setRange("month"); fetchStats(); }}>本月</Text>
98	      </View>
99	
100	      <View className="metrics">
101	        <View className="metric"><Text className="metric-value">{overallRate}%</Text><Text className="metric-label">总完成率</Text></View>
102	        <View className="metric"><Text className="metric-value">{totalChecks}</Text><Text className="metric-label">总打卡数</Text></View>
103	        <View className="metric">
104	          <Text className="metric-value">{streakDays}</Text>
105	          <Text className="metric-label">连续天数</Text>
106	          <Text className="metric-sub">连续精进 {streakDays} 天（完成率≥80%）</Text>
107	        </View>
108	        <View className="metric"><Text className="metric-value">{habits.length}</Text><Text className="metric-label">活跃习惯</Text></View>
109	      </View>
110	
111	      {/* Bar Chart */}
112	      <View className="chart-card">
113	        <Text className="chart-title">每日完成趋势</Text>
114	        <View className="bar-row">
115	          {barData.map((d, i) => (
116	            <View key={i} className="bar-col">
117	              <View className="bar" style={{ height: `${Math.max(d.pct, 4)}%`, background: d.completed > 0 ? "var(--color-accent)" : "var(--color-border)" }} />
118	              <Text className="bar-label">{d.label}</Text>
119	            </View>
120	          ))}
121	        </View>
122	      </View>
123	
124	      {/* Domain Rates */}
125	      <View className="chart-card">
126	        <Text className="chart-title">领域均衡度</Text>
127	        {domainStats.map((d) => (
128	          <View key={d.name} className="domain-row">
129	            <View className="domain-name">
130	              <Icon name={d.icon as import("../../components/Icon").IconName} size={32} color="accent" />
131	              <Text> {d.name}</Text>
132	            </View>
133	            <View className="domain-bar-bg">
134	              <View className="domain-bar-fill" style={{ width: `${d.rate}%`, background: d.color }} />
135	            </View>
136	            <Text className="domain-rate">{d.rate}%</Text>
137	          </View>
138	        ))}
139	      </View>
140	    </View>
141	  );
142	}
143	
144	function countWeekdays(days: number): number {
145	  let count = 0;
146	  const now = new Date();
147	  for (let i = 0; i < days; i++) {
148	    const d = new Date(now);
149	    d.setDate(d.getDate() - i);
150	    const day = d.getDay();
151	    if (day >= 1 && day <= 5) count++;
152	  }
153	  return count;
154	}
155	
156	function calcStreak(habits: HabitWithLogs[]): number {
157	  if (habits.length === 0) return 0;
158	  const dailyHabits = habits.filter((h) => h.frequency === "daily");
159	  if (dailyHabits.length === 0) return 0;
160	  let streak = 0;
161	  const today = new Date(getToday());
162	  for (let i = 0; ; i++) {
163	    const d = new Date(today);
164	    d.setDate(d.getDate() - i);
165	    const dateStr = d.toISOString().split("T")[0];
166	    let completed = 0;
167	    for (const h of dailyHabits) {
168	      const log = h.logs.find((l) => l.date === dateStr);
169	      if (log && log.completed) completed++;
170	    }
171	    const rate = completed / dailyHabits.length;
172	    if (rate >= 0.8) streak++;
173	    else break;
174	  }
175	  return streak;
176	}
