50	
51	  async function fetchHabits() {
52	    try {
53	      setHabits(await apiFetch("/api/habits"));
54	    } catch (e: any) {
55	      console.error("[fetchHabits]", e);
56	      showToast({ title: "获取习惯列表失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
57	    }
58	    setLoading(false);
