62	    setEditId(null);
63	    setForm({ title: "", description: "", domainIdx: 0, unit: "次", targetValue: 1, frequency: "daily" });
64	    setFormDirty(false);
65	    setShowForm(true);
66	  }
67	
68	  function openEdit(h: Habit) {
69	    setEditId(h.id);
70	    const domains = getDomains();
71	    const idx = domains.findIndex(d => d.name === h.domainId);
72	    setForm({
