74	      description: h.description || "",
75	      domainIdx: idx >= 0 ? idx : domains.length - 1,
76	      unit: h.unit,
77	      targetValue: h.targetValue,
78	      frequency: h.frequency,
79	    });
80	    setFormDirty(false);
81	    setShowForm(true);
