118	  async function deleteHabit(id: string) {
119	    try {
120	      await apiFetch("/api/habits", { method: "DELETE", body: JSON.stringify({ id }) });
121	      fetchHabits();
122	    } catch (e: any) {
123	      console.error("[deleteHabit]", e);
124	      showToast({ title: "删除习惯失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
125	    }
126	  }
