128	  async function toggleActive(id: string, current: boolean) {
129	    try {
130	      await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id, isActive: !current }) });
131	      fetchHabits();
132	    } catch (e: any) {
133	      console.error("[toggleActive]", e);
134	      showToast({ title: "操作失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
