159	  async function handleDomainSave() {
160	    const name = domainForm.name.trim();
161	    if (!name) return;
162	
163	    const userDomains = getDomains().filter(d => d.name !== UNCATEGORIZED.name);
164	
165	    if (domainManagerView === "new") {
166	      if (userDomains.some(d => d.name === name)) {
167	        showModal({ title: "提示", content: "该领域名称已存在", showCancel: false });
168	        return;
169	      }
170	      userDomains.push({ name, icon: domainForm.icon, color: domainForm.color });
171	    } else if (domainManagerView === "edit") {
172	      const idx = userDomains.findIndex(d => d.name === editingDomainName);
173	      if (idx === -1) return;
174	
175	      if (name !== editingDomainName && userDomains.some(d => d.name === name)) {
176	        showModal({ title: "提示", content: "该领域名称已存在", showCancel: false });
177	        return;
178	      }
179	
180	      const oldName = userDomains[idx].name;
181	      userDomains[idx] = { name, icon: domainForm.icon, color: domainForm.color };
182	
183	      // If domain renamed, update all habits under old name
184	      if (name !== oldName) {
185	        try {
186	          await Promise.all(habits.filter(h => h.domainId === oldName).map(h =>
187	            apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: h.id, domainId: name }) })
188	          ));
189	          fetchHabits();
190	        } catch (e: any) {
191	          console.error("[handleDomainSave-migrate]", e);
192	          showToast({ title: "迁移习惯失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
193	          return;
194	        }
195	      }
196	    }
197	
198	    saveDomains(userDomains);
199	    setDomainManagerView("list");
200	    setEditingDomainName(null);
201	  }
202	
203	  async function handleDeleteDomain(domain: Domain) {
204	    const count = habits.filter(h => h.domainId === domain.name).length;
205	    const res = await showModal({
206	      title: "删除领域",
207	      content: `确定删除"${domain.name}"吗？其下 ${count} 个习惯将移入"未分类"。`,
208	    });
209	
210	    if (!res.confirm) return;
211	
212	    setSaving(true);
213	    try {
214	      // Move habits to 未分类 first, then delete domain
215	      await Promise.all(habits.filter(h => h.domainId === domain.name).map(h =>
216	        apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: h.id, domainId: UNCATEGORIZED.name }) })
217	      ));
218	
219	      const userDomains = getDomains()
220	        .filter(d => d.name !== UNCATEGORIZED.name && d.name !== domain.name);
221	      saveDomains(userDomains);
222	
223	      fetchHabits();
224	    } catch (e: any) {
225	      console.error("[handleDeleteDomain]", e);
226	      showToast({ title: "删除领域失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
227	    } finally {
228	      setSaving(false);
229	    }
230	  }
231	
232	  const domains = getDomains();
233	
234	  return (
235	    <View className="page">
236	      <View className="page-header">
