251	            </View>
252	            {domainHabits.map((habit) => (
253	              <View key={habit.id} className={`habit-card ${!habit.isActive ? "inactive" : ""}`}>
254	                <View className="habit-info">
255	                  <Text className="habit-name">{habit.title}</Text>
256	                  {habit.description && <Text className="habit-desc">{habit.description}</Text>}
257	                  <View className="habit-meta">
258	                    <Text>{habit.frequency === "daily" ? "每日" : habit.frequency}</Text>
259	                    <Text> · </Text>
260	                    <Text>目标 {habit.targetValue}{habit.unit}</Text>
261	                  </View>
262	                </View>
263	                <View className="habit-actions">
264	                  <Text className={`action-btn ${saving ? "disabled" : ""}`} onClick={() => !saving && toggleActive(habit.id, habit.isActive)}>
265	                    {habit.isActive ? "停用" : "启用"}
266	                  </Text>
267	                  <Text className="action-btn" onClick={() => openEdit(habit)}>编辑</Text>
268	                  <Text className={`action-btn danger ${saving ? "disabled" : ""}`} onClick={() => !saving && deleteHabit(habit.id)}>删除</Text>
269	                </View>
270	              </View>
271	            ))}
272	          </View>
273	        );
274	      })}
275	
276	      <View className="domain-manager-entry" onClick={openDomainManager}>
277	        <View className="domain-manager-entry-bar" />
278	        <Text className="domain-manager-entry-text">管理分类</Text>
279	        <Text className="domain-manager-entry-arrow">&#8250;</Text>
280	      </View>
281	
282	      {!loading && habits.length === 0 && (
283	        <View className="empty"><Text>还没有习惯，点右上角 + 开始</Text></View>
284	      )}
285	
286	      {/* ---- Habit Form Modal ---- */}
287	      {showForm && (
288	        <View className="modal-mask" onClick={handleCloseForm}>
289	          <View className="modal" onClick={(e) => e.stopPropagation()}>
290	            <Text className="modal-title">{editId ? "编辑习惯" : "新增习惯"}</Text>
291	
292	            <View className="form-group">
293	              <Text className="form-label">名称</Text>
294	              <Input className="form-input" placeholder="如：晨跑30分钟" value={form.title} onInput={(e) => { setForm({ ...form, title: e.detail.value }); setFormDirty(true); }} />
295	            </View>
296	
297	            <View className="form-group">
298	              <Text className="form-label">描述</Text>
299	              <Input className="form-input" placeholder="具体怎么做" value={form.description} onInput={(e) => { setForm({ ...form, description: e.detail.value }); setFormDirty(true); }} />
300	            </View>
301	
302	            <View className="form-row">
303	              <View className="form-group flex-1">
304	                <Text className="form-label">领域</Text>
305	                <Picker mode="selector" range={domains.map(d => d.name)} value={form.domainIdx} onChange={(e) => { setForm({ ...form, domainIdx: +e.detail.value }); setFormDirty(true); }}>
306	                  <View className="form-picker">
307	                    <Icon name={domains[form.domainIdx].icon as IconName} size={32} color="accent" />
308	                    <Text> {domains[form.domainIdx].name}</Text>
309	                  </View>
310	                </Picker>
311	              </View>
312	              <View className="form-group flex-1">
313	                <Text className="form-label">频率</Text>
314	                <Picker mode="selector" range={["每日", "每周", "工作日"]} value={form.frequency === "daily" ? 0 : form.frequency === "weekly" ? 1 : 2} onChange={(e) => { setForm({ ...form, frequency: ["daily", "weekly", "weekday"][+e.detail.value] }); setFormDirty(true); }}>
315	                  <View className="form-picker">{form.frequency === "daily" ? "每日" : form.frequency === "weekly" ? "每周" : "工作日"}</View>
316	                </Picker>
317	              </View>
318	            </View>
319	
320	            <View className="form-row">
321	              <View className="form-group flex-1">
322	                <Text className="form-label">目标值</Text>
323	                <Input className="form-input" type="number" value={String(form.targetValue)} onInput={(e) => { setForm({ ...form, targetValue: +e.detail.value || 1 }); setFormDirty(true); }} />
324	              </View>
325	              <View className="form-group flex-1">
326	                <Text className="form-label">单位</Text>
327	                <Input className="form-input" placeholder="次/分钟/页" value={form.unit} onInput={(e) => { setForm({ ...form, unit: e.detail.value }); setFormDirty(true); }} />
328	              </View>
329	            </View>
330	
331	            <View className="form-buttons">
332	              <View className="btn-cancel" onClick={handleCloseForm}><Text>取消</Text></View>
333	              <View className={"btn-save" + (saving ? " disabled" : "")} onClick={() => !saving && handleSave()}><Text>{editId ? "保存" : "添加"}</Text></View>
334	            </View>
335	          </View>
336	        </View>
337	      )}
338	
339	      {/* ---- Domain Manager Modal ---- */}
340	      {showDomainManager && (
341	        <View className="modal-mask" onClick={() => setShowDomainManager(false)}>
342	          <View className="modal" onClick={(e) => e.stopPropagation()}>
343	            <View className="domain-manager-accent" />
344	
345	            {/* List View */}
346	            {domainManagerView === "list" && (
