382	            )}
383	
384	            {/* New / Edit Form View */}
385	            {(domainManagerView === "new" || domainManagerView === "edit") && (
386	              <>
387	                <Text className="modal-title">{domainManagerView === "new" ? "新增分类" : "编辑分类"}</Text>
388	
389	                <View className="form-group">
