8	export default function ReviewPage() {
9	  const [form, setForm] = useState({ score: 3, summary: "", highlight: "", lowlight: "", userSupplement: "" });
10	  const [submitted, setSubmitted] = useState(false);
11	  const [aiFeedback, setAiFeedback] = useState("");
12	  const [review, setReview] = useState<any>(null);
13	  const [aiSummary, setAiSummary] = useState("");
14	  const [aiSummaryError, setAiSummaryError] = useState(false);
15	  const [summaryLoading, setSummaryLoading] = useState(true);
16	
17	  useDidShow(() => {
18	    const today = getToday();
19	
20	    // Fetch existing review
21	    apiFetch(`/api/review?date=${today}`).then((data) => {
22	      if (data?.id) {
23	        setReview(data);
24	        setForm({
25	          score: data.score,
26	          summary: data.summary || "",
27	          highlight: data.highlight || "",
28	          lowlight: data.lowlight || "",
29	          userSupplement: data.userSupplement || "",
30	        });
31	        setAiFeedback(data.aiFeedback || "");
32	        setAiSummary(data.aiSummary || "");
33	        setSubmitted(true);
34	      }
35	    }).catch(() => {
36	      Taro.showToast({ title: "获取复盘数据失败", icon: "none" });
37	    });
38	
39	    // Fetch AI daily summary
40	    setSummaryLoading(true);
41	    setAiSummaryError(false);
42	    apiFetch("/api/insights", {
43	      method: "POST",
44	      body: JSON.stringify({ type: "daily-summary" }),
45	    }).then((res) => {
46	      const text = res?.text || "";
47	      if (text && text !== "今日尚未打卡，完成日课后自动生成小结。") {
48	        setAiSummary(text);
49	      } else {
50	        setAiSummary(text || "");
51	      }
52	      setSummaryLoading(false);
53	    }).catch(() => {
54	      setAiSummaryError(true);
55	      setSummaryLoading(false);
56	    });
57	  });
58	
59	  async function handleSubmit() {
60	    const today = getToday();
61	    const data = await apiFetch("/api/review", {
62	      method: "POST",
63	      body: JSON.stringify({
64	        ...form,
65	        date: today,
66	        aiSummary: aiSummary || null,
67	        userSupplement: form.userSupplement || null,
68	      }),
69	    });
70	    setSubmitted(true);
71	    setReview(data);
72	    try {
73	      const ai = await apiFetch("/api/insights", {
74	        method: "POST",
75	        body: JSON.stringify({ type: "review", data: form }),
76	      });
77	      setAiFeedback(ai.text || "");
78	    } catch {}
79	  }
80	
81	  function renderAiSummaryCard() {
82	    if (summaryLoading) {
83	      return (
84	        <View className="ai-summary-card">
85	          <View className="ai-summary-header">
86	            <Icon name="bot" size={40} color="accent" />
87	            <Text className="ai-summary-title">今日小结</Text>
88	          </View>
89	          <View className="skeleton-lines">
90	            <View className="skeleton-line w-80" />
91	            <View className="skeleton-line w-60" />
92	            <View className="skeleton-line w-70" />
93	          </View>
94	        </View>
95	      );
96	    }
97	
98	    if (aiSummaryError) {
99	      return (
100	        <View className="ai-summary-card ai-summary-fallback">
101	          <View className="ai-summary-header">
102	            <Icon name="bot" size={40} color="accent" />
103	            <Text className="ai-summary-title">今日小结</Text>
104	          </View>
105	          <Text className="ai-summary-fallback-text">今日小结暂不可用</Text>
106	        </View>
107	      );
108	    }
109	
110	    return (
111	      <View className="ai-summary-card">
112	        <View className="ai-summary-header">
113	          <Icon name="bot" size={40} />
114	          <Text className="ai-summary-title">今日小结</Text>
115	        </View>
116	        {aiSummary ? (
117	          <Text className="ai-summary-text">{aiSummary}</Text>
118	        ) : (
119	          <Text className="ai-summary-empty-text">
120	            今日尚未打卡，完成日课后自动生成小结
121	          </Text>
122	        )}
123	        <Textarea
124	          className="ai-summary-supplement"
125	          placeholder="在此写下你的补充感悟..."
126	          value={form.userSupplement}
127	          onInput={(e) => setForm({ ...form, userSupplement: e.detail.value })}
128	          maxlength={500}
129	        />
130	      </View>
131	    );
132	  }
133	
134	  // ---- Result view ----
135	  if (review && submitted) {
136	    return (
137	      <View className="page">
138	        <Text className="page-title">每日复盘</Text>
139	
140	        {renderAiSummaryCard()}
141	
142	        <View className="review-card center">
143	          <Text className="review-score">
144	          <Icon
145	            name={(["", "mood-1", "mood-2", "mood-3", "mood-4", "mood-5"] as IconName[])[review.score]}
146	            size={96}
147	          />
148	          </Text>
149	          <Text className="review-summary">今日评分 {review.score}/5</Text>
150	          <Text className="review-summary">{review.summary}</Text>
151	        </View>
152	
153	        {aiFeedback ? (
154	          <View className="ai-card">
155	            <View className="ai-title-row">
156	              <Icon name="award" size={40} color="accent" />
157	              <Text className="ai-title">AI 教练点评</Text>
158	            </View>
159	            <Text className="ai-text">{aiFeedback}</Text>
160	          </View>
161	        ) : null}
162	
163	        <View className="split-cards">
164	          <View className="split-card">
165	            <Text className="split-label">今日亮点</Text>
166	            <Text className="split-text">{review.highlight || "—"}</Text>
167	          </View>
168	          <View className="split-card">
169	            <Text className="split-label">待改进</Text>
170	            <Text className="split-text">{review.lowlight || "—"}</Text>
171	          </View>
172	        </View>
173	        <View className="submit-btn" onClick={() => setSubmitted(false)}>
174	          <Text>编辑复盘</Text>
175	        </View>
176	      </View>
177	    );
178	  }
179	
180	  // ---- Edit form view ----
181	  return (
182	    <View className="page">
183	      <Text className="page-title">每日复盘</Text>
184	      <Text className="page-subtitle">三省吾身，日日精进</Text>
185	
186	      {renderAiSummaryCard()}
187	
188	      <View className="review-card">
