205	        <View className="form-group">
206	          <Text className="form-label">今日亮点</Text>
207	          <Textarea className="form-textarea" placeholder="最值得骄傲的事" value={form.highlight} onInput={(e) => setForm({ ...form, highlight: e.detail.value })} maxlength={500} />
208	        </View>
