9	export default function ProfilePage() {
10	  const [profile, setProfile] = useState({
11	    name: "", goals: "", wakeTime: "07:00", sleepTime: "23:00", customPrompt: "",
12	  });
13	  const [inputs, setInputs] = useState<{ category: string; content: string }[]>([]);
14	  const [newInput, setNewInput] = useState({ category: "健身", content: "" });
15	  const [saved, setSaved] = useState(false);
16	  const [loading, setLoading] = useState(true);
17	  const [reminderEnabled, setReminderEnabled] = useState(false);
18	  const [reminderTime, setReminderTime] = useState("21:00");
19	  const [reminderDays, setReminderDays] = useState<number[]>([1, 2, 3, 4, 5, 6, 7]);
20	
21	  useDidShow(() => {
22	    setLoading(true);
23	    apiFetch("/api/profile").then((data) => {
24	      if (data.profile) {
25	        setProfile({
26	          name: data.profile.name || "",
27	          goals: Array.isArray(data.profile.goals) ? data.profile.goals.join("\n") : "",
28	          wakeTime: data.profile.wakeTime || "07:00",
29	          sleepTime: data.profile.sleepTime || "23:00",
30	          customPrompt: data.profile.preferences?.customPrompt || "",
31	        });
32	        const reminder = data.profile.reminder || {};
33	        setReminderEnabled(reminder.enabled || false);
34	        setReminderTime(reminder.time || "21:00");
35	        setReminderDays(reminder.days || [1, 2, 3, 4, 5, 6, 7]);
36	      }
37	      if (data.inputs) setInputs(data.inputs);
38	      setLoading(false);
39	    }).catch(() => {
40	      Taro.showToast({ title: "获取个人资料失败", icon: "none" });
41	      setLoading(false);
42	    });
43	  });
44	
45	  async function saveProfile() {
46	    try {
47	      await apiFetch("/api/profile", {
48	        method: "POST",
49	        body: JSON.stringify({
50	          name: profile.name,
51	          goals: profile.goals.split("\n").filter((g) => g.trim()),
52	          wakeTime: profile.wakeTime,
53	          sleepTime: profile.sleepTime,
54	          customPrompt: profile.customPrompt,
55	        }),
56	      });
57	      setSaved(true);
58	      setTimeout(() => setSaved(false), 2000);
59	    } catch {
60	      Taro.showToast({ title: "保存设置失败", icon: "none" });
61	    }
62	  }
63	
64	  const REMINDER_TEMPLATE_ID = "TEMPLATE_ID";
65	
66	  async function saveReminder(enabled: boolean, time: string, days: number[]) {
67	    try {
68	      await apiFetch("/api/profile", {
69	        method: "POST",
70	        body: JSON.stringify({ reminder: { enabled, time, days } }),
71	      });
72	    } catch (e) {
73	      Taro.showToast({ title: "保存失败，请稍后重试", icon: "none" });
74	      throw e;
75	    }
76	  }
77	
78	  async function handleReminderToggle(value: boolean) {
79	    if (value) {
80	      try {
81	        const res: Record<string, string> = await (Taro as any).requestSubscribeMessage({
82	          tmplIds: [REMINDER_TEMPLATE_ID],
83	        });
84	        if (res[REMINDER_TEMPLATE_ID] !== "accept") {
85	          Taro.showToast({ title: "需要授权才能开启每日提醒", icon: "none" });
86	          return;
87	        }
88	      } catch {
89	        Taro.showToast({ title: "授权失败，请稍后重试", icon: "none" });
90	        return;
91	      }
92	    }
93	    await saveReminder(value, reminderTime, reminderDays);
94	    setReminderEnabled(value);
95	    Taro.showToast({
96	      title: value ? "每日提醒已开启" : "每日提醒已关闭",
97	      icon: "success",
98	    });
99	  }
100	
101	  async function handleReminderTimeChange(time: string) {
102	    if (reminderEnabled) {
103	      await saveReminder(true, time, reminderDays);
104	    }
105	    setReminderTime(time);
106	  }
107	
108	  async function handleReminderDayToggle(day: number) {
109	    const newDays = reminderDays.includes(day)
110	      ? reminderDays.filter((d) => d !== day)
111	      : [...reminderDays, day];
112	    if (newDays.length === 0) return;
113	    if (reminderEnabled) {
114	      await saveReminder(true, reminderTime, newDays);
115	    }
116	    setReminderDays(newDays);
117	  }
118	
119	  async function addInput() {
120	    if (!newInput.content.trim()) return;
121	    await apiFetch("/api/profile/input", {
122	      method: "POST",
123	      body: JSON.stringify(newInput),
124	    });
125	    setInputs([...inputs, newInput]);
126	    setNewInput({ category: "健身", content: "" });
127	  }
128	
129	  return (
130	    <View className="page">
131	      <Text className="page-title">个人设置</Text>
132	      <Text className="page-subtitle">越了解你，越能精准辅助</Text>
133	
134	      {loading ? (
135	        <View className="skeleton-lines" style={{ marginTop: "var(--space-xl)" }}>
136	          <View className="skeleton-line w-80" />
137	          <View className="skeleton-line w-60" />
138	          <View className="skeleton-line w-70" />
139	          <View className="skeleton-line w-50" />
140	        </View>
141	      ) : (
142	        <>
143	        <View className="card">
144	          <Text className="card-title">基本信息</Text>
145	          <View className="form-group">
146	            <Text className="form-label">你的名字/称号</Text>
147	            <Input className="form-input" placeholder="朕 / 陛下" value={profile.name} onInput={(e) => setProfile({ ...profile, name: e.detail.value })} />
148	          </View>
149	          <View className="form-row">
150	            <View className="form-group flex-1">
151	              <Text className="form-label">起床时间</Text>
152	              <Picker mode="time" value={profile.wakeTime} onChange={(e) => setProfile({ ...profile, wakeTime: e.detail.value })}>
153	                <View className="form-input" style={{ display: "flex", alignItems: "center" }}><Text>{profile.wakeTime}</Text></View>
154	              </Picker>
155	            </View>
156	            <View className="form-group flex-1">
157	              <Text className="form-label">睡觉时间</Text>
158	              <Picker mode="time" value={profile.sleepTime} onChange={(e) => setProfile({ ...profile, sleepTime: e.detail.value })}>
159	                <View className="form-input" style={{ display: "flex", alignItems: "center" }}><Text>{profile.sleepTime}</Text></View>
160	              </Picker>
161	            </View>
162	          </View>
163	        </View>
164	
165	        <View className="card">
166	          <Text className="card-title">你的目标</Text>
167	          <Textarea className="form-textarea" placeholder={"提升商业分析能力\n养成运动习惯\n扩大社交圈\n..."} value={profile.goals} onInput={(e) => setProfile({ ...profile, goals: e.detail.value })} />
168	        </View>
169	
170	        <View className="card">
171	          <Text className="card-title">AI 个性化提示词</Text>
172	          <Textarea className="form-textarea" placeholder={"用「陛下」称呼我\n关注商业和管理领域\n多推荐前沿科技内容"} value={profile.customPrompt} onInput={(e) => setProfile({ ...profile, customPrompt: e.detail.value })} />
173	        </View>
174	
175	        <View className="save-btn" onClick={saveProfile}>
176	          {saved ? (
177	            <View className="save-btn-content">
178	              <Icon name="check" size={32} color="accent" />
179	              <Text>已保存</Text>
180	            </View>
181	          ) : (
182	            <Text>保存设置</Text>
183	          )}
184	        </View>
185	
186	        <ReminderCard
187	          enabled={reminderEnabled}
188	          time={reminderTime}
189	          days={reminderDays}
190	          onToggle={handleReminderToggle}
191	          onTimeChange={handleReminderTimeChange}
192	          onDayToggle={handleReminderDayToggle}
193	        />
194	
195	        <View className="card" onClick={() => Taro.navigateTo({ url: "/pages/insights/index" })}>
196	          <View className="card-title-row">
197	            <Text className="card-title">AI 洞察</Text>
198	            <Text className="card-arrow">&#8250;</Text>
199	          </View>
200	          <Text className="card-desc">查看每周 AI 洞察与习惯建议</Text>
201	        </View>
202	
203	        <View className="card">
204	          <Text className="card-title">个性化需求</Text>
205	          <View style={{ marginBottom: "20rpx" }}>
206	            {inputs.map((pi, i) => (
207	              <Text key={i} className="input-tag">{pi.category}: {pi.content}</Text>
208	            ))}
209	          </View>
210	          <View className="input-row">
211	            <Picker mode="selector" range={PRESET_DOMAINS.map(d => d.name)} value={PRESET_DOMAINS.findIndex(d => d.name === newInput.category)} onChange={(e) => setNewInput({ ...newInput, category: PRESET_DOMAINS[+e.detail.value].name })}>
212	              <View className="form-input" style={{ width: "160rpx", display: "flex", alignItems: "center" }}><Text>{newInput.category}</Text></View>
213	            </Picker>
214	            <Input className="form-input" style={{ flex: 1 }} placeholder="描述你的个性化需求..." value={newInput.content} onInput={(e) => setNewInput({ ...newInput, content: e.detail.value })} onConfirm={addInput} />
215	            <Text className="add-btn" onClick={addInput}>添加</Text>
216	          </View>
217	        </View>
218	        </>
219	      )}
220	    </View>
221	  );
222	}
