1	import { useState } from "react";
2	import { View, Text, Textarea } from "@tarojs/components";
3	import Taro from "@tarojs/taro";
4	import { apiFetch } from "../../lib";
5	import Icon from "../../components/Icon";
6	import "./index.scss";
7	
8	export default function InsightsPage() {
9	  const [insights, setInsights] = useState("");
10	  const [loading, setLoading] = useState(false);
11	  const [habitPrompt, setHabitPrompt] = useState("");
12	  const [generated, setGenerated] = useState("");
13	
14	  async function getWeeklyInsight() {
15	    setLoading(true);
16	    try {
17	      const data = await apiFetch("/api/insights", {
18	        method: "POST",
19	        body: JSON.stringify({ type: "weekly" }),
20	      });
21	      setInsights(data.text || "");
22	    } catch {
23	      Taro.showToast({ title: "获取洞察失败", icon: "none" });
24	    } finally {
25	      setLoading(false);
26	    }
27	  }
28	
29	  async function generateHabits() {
30	    if (!habitPrompt.trim()) return;
31	    setLoading(true);
32	    try {
33	      const data = await apiFetch("/api/insights", {
34	        method: "POST",
35	        body: JSON.stringify({ type: "generate-habits", prompt: habitPrompt }),
36	      });
37	      setGenerated(data.text || "");
38	    } catch {
39	      Taro.showToast({ title: "生成习惯方案失败", icon: "none" });
40	    } finally {
41	      setLoading(false);
42	    }
43	  }
44	
45	  return (
46	    <View className="page">
47	      <Text className="page-title">AI 洞察</Text>
48	      <Text className="page-subtitle">发现规律，精准提升</Text>
49	
50	      <View className="card">
51	        <View className="card-title-row">
52	          <Icon name="sparkles" size={40} color="accent" />
53	          <Text className="card-title">本周洞察</Text>
54	        </View>
55	        {insights ? (
56	          <Text className="insight-text">{insights}</Text>
57	        ) : (
58	          <Text className="card-desc">根据你的打卡数据生成个性化一周分析报告</Text>
59	        )}
60	        <Text className="action-btn" onClick={getWeeklyInsight}>
61	          {loading ? "生成中..." : "生成本周洞察"}
62	        </Text>
63	      </View>
64	
65	      <View className="card">
66	        <View className="card-title-row">
67	          <Icon name="target" size={40} color="accent" />
68	          <Text className="card-title">习惯生成器</Text>
69	        </View>
70	        <Text className="card-desc">描述你的目标，AI 帮你拆解为可执行的习惯</Text>
71	        <Textarea
72	          className="textarea"
73	          placeholder="例如：我想提升商业分析能力，每天只有1小时空闲时间..."
74	          value={habitPrompt}
75	          onInput={(e) => setHabitPrompt(e.detail.value)}
76	        />
77	        <Text className="action-btn" onClick={generateHabits}>
78	          {loading ? "生成中..." : "生成习惯方案"}
79	        </Text>
80	        {generated ? (
81	          <Text className="insight-text" style={{ marginTop: "20rpx" }}>{generated}</Text>
82	        ) : null}
83	      </View>
84	    </View>
85	  );
86	}
