function getMonthHeatmap(habits: HabitWithLogs[], range: "week" | "month") {
  if (range !== "month") return [];

  const now = new Date();
  const year = now.getFullYear();
  const month = now.getMonth();

  // First day of month
  const firstDay = new Date(year, month, 1);
  const lastDay = new Date(year, month + 1, 0);

  const totalDays = lastDay.getDate();

  // Build weeks
  const weeks: WeekRow[] = [];
  let currentWeek: WeekRow['days'] = [];
  let weekStart = 1;

  // Pad days before the first day of month
  const firstDayOfWeek = firstDay.getDay(); // 0=Sun
  // Convert to Mon=1...Sun=7
  const firstDayOfWeekMon = firstDayOfWeek === 0 ? 7 : firstDayOfWeek;

  for (let d = 1; d <= totalDays; d++) {
    const date = new Date(year, month, d);
    const dayOfWeek = date.getDay(); // 0=Sun
    const dayOfWeekMon = dayOfWeek === 0 ? 7 : dayOfWeek;

    const dateStr = date.toISOString().split("T")[0];

    // Check completion for this date
    const total = habits.length;
    const completed = habits.filter(h => h.logs.some(l => l.date === dateStr && l.completed)).length;

    let status: "none" | "partial" | "full";
    if (total === 0) {
