```ts
function computeHeatmap(habits: HabitWithLogs[], year: number, month: number) {
  const firstDay = new Date(year, month, 1);
  const lastDay = new Date(year, month + 1, 0);
  const totalDays = lastDay.getDate();

  // 0=Sun in JS, convert to 0=Mon for display
  const startDow = (firstDay.getDay() + 6) % 7; // 0=Mon, 1=Tue, ..., 6=Sun

  const cells = [];
  let dayCount = 0;

  for (let row = 0; row < 6; row++) {
    const week = [];
    for (let col = 0; col < 7; col++) {
      if ((row === 0 && col < startDow) || dayCount >= totalDays) {
        week.push({ date: null, status: "empty" });
      } else {
        dayCount++;
        const d = new Date(year, month, dayCount);
        const dateStr = d.toISOString().split("T")[0];
        const total = habits.length;
        const completed = habits.filter(h => h.logs.some(l => l.date === dateStr && l.completed)).length;

        let status: "none" | "partial" | "full";
        if (total === 0 || completed === 0) status = "none";
        else if (completed / total >= 0.8) status = "full";
        else status = "partial";

        week.push({ date: dateStr, dayNum: dayCount, status });
      }
    }
    cells.push(week);
    if (dayCount >= totalDays) break;
  }

  return cells;
}
```

