function renderHeatmap() {
  const now = new Date();
  const year = now.getFullYear();
  const month = now.getMonth();
  const lastDay = new Date(year, month + 1, 0).getDate();

  // 0=Sun in JS -> convert to 0=Mon for our grid
  const firstDay = new Date(year, month, 1);
  const startDow = (firstDay.getDay() + 6) % 7; // 0=Mon..6=Sun

  const DAY_LABELS = ["一", "二", "三", "四", "五", "六", "日"];

  // Build weeks
  let dayCount = 0;
  const weeks: { startDay: number; days: { dayNum: number; status: string }[] }[] = [];

  for (let row = 0; row < 6; row++) {
    if (dayCount >= lastDay) break;
    const days: { dayNum: number; status: string }[] = [];
    let weekStart = 0;
    for (let col = 0; col < 7; col++) {
      if ((row === 0 && col < startDow) || dayCount >= lastDay) {
        days.push({ dayNum: 0, status: "empty" });
      } else {
        dayCount++;
        const d = new Date(year, month, dayCount);
        const dateStr = d.toISOString().split("T")[0];
        const total = habits.length;
        const completed = habits.filter(h => h.logs.some(l => l.date === dateStr && l.completed)).length;

        let status: string;
        if (total === 0 || completed === 0) status = "none";
        else if (completed / total >= 0.8) status = "full";
        else status = "partial";

        if (weekStart === 0) weekStart = dayCount;
        days.push({ dayNum: dayCount, status });
      }
    }
    weeks.push({ startDay: weekStart, days });
  }

  return (
    <View className="heatmap">
      <View className="heatmap-header">
        <View className="heatmap-corner" />
        {DAY_LABELS.map((label, i) => (
          <Text key={i} className="heatmap-col-label">{label}</Text>
        ))}
      </View>
      {weeks.map((week, wi) => (
        <View key={wi} className="heatmap-row">
          <View className="heatmap-row-label">
            <Text className="heatmap-week-label">第{wi + 1}周</Text>
            <Text className="heatmap-week-start">{String(week.startDay).padStart(2, "0")}</Text>
          </View>
          {week.days.map((day, di) => (
            <View key={di} className={`heatmap-cell heatmap-cell-${day.status}`} />
          ))}
        </View>
      ))}
    </View>
  );
}
