          <View className="bar" style={{ height: `${Math.max(d.pct, 4)}%`, background: d.completed > 0 ? "var(--color-accent)" : "var(--color-border)" }} />
          <Text className="bar-label">{d.label}</Text>
        </View>
      ))}
