  background: var(--color-accent-subtle);
  border: 2rpx solid var(--color-accent);
  opacity: 0.5;
}

.heatmap-cell-full {
  background: var(--color-accent);
  border: 2rpx solid var(--color-accent);
  box-shadow: 0 0 6rpx var(--color-accent-subtle);
}

